builder.Services.AddOutputCache(opt =>
{
    opt.AddPolicy("products", b => b
        .Cache()
        .Expire(TimeSpan.FromMinutes(5))
        .SetVaryByQuery("category", "page")
        .Tag("products")); // để invalidate theo tag
});

app.UseOutputCache();

app.MapGet("/api/products", async (ProductService svc, CancellationToken ct) =>
    await svc.GetListAsync(ct))
   .CacheOutput("products");

// Invalidate khi data thay đổi
app.MapPost("/api/products", async (
    CreateProductDto dto, ProductService svc,
    IOutputCacheStore cache, CancellationToken ct) =>
{
    var product = await svc.CreateAsync(dto, ct);
    await cache.EvictByTagAsync("products", ct); // xóa cache "products"
    return Results.Created($"/api/products/{product.Id}", product);
});

// .NET 8+: Redis store
builder.Services.AddStackExchangeRedisOutputCache(opt =>
    opt.Configuration = builder.Configuration["Redis"]);
